    public static void promptCopyData(RecId _policyRecId)
    {
        next promptCopyData(_policyRecId);

        SysDataSharingOrganizationEnabled org;
        SysDataSharingRuleEnabled         ruleEnabled;
        SysDataSharingPolicy              sharingPolicy;

        List            sharedList      = SysDataSharingSqlObjects::getTopologicalOrdering(_policyRecId);
        ListEnumerator  listEnum        = sharedList.getEnumerator();

        while (listEnum.moveNext())
        {
            select firstonly SharedTableName from ruleEnabled
                        where ruleEnabled.RecId == listEnum.current();

            if(ruleEnabled.SharedTableName == tableStr(VendTable))
            {
                select firstfast org where org.DataSharingPolicy == _policyRecId;   
                DataAreaId destinationAreaId = org.DataSharingCompany;

                UBSTriggerDimensionDefaultingList dimensionDefaulting = UBSTriggerDimensionDefaultingList::construct();
                dimensionDefaulting.batchInfo().parmBatchExecute(NoYes::Yes);
                dimensionDefaulting.batchInfo().parmCaption('@UBS:UBSSyncDefaultDimVendor');
                dimensionDefaulting.parmSourceEntity(destinationAreaId);
        
                BatchHeader batchHeader = BatchHeader::construct();
                batchHeader.addTask(dimensionDefaulting);
                batchHeader.save();
            }
        }

    }
